"8-3": [
  {desc:"写安全计算器：处理非数字和除零错误", template:'# 安全计算器\n', hint:'def safe_calc(a, op, b):\n    try:\n        a, b = float(a), float(b)\n        if op == "+": return a + b\n        elif op == "/": return a / b\n    except ValueError: return "请输入数字"\n    except ZeroDivisionError: return "不能除以零"\nprint(safe_calc("10","+","5"))\nprint(safe_calc("10","/","0"))', check:function(o){return o.trim().split("\n").length>=2;}},
  {desc:"用try/except捕获IndexError", template:'nums = [1, 2, 3]\n', hint:'nums = [1, 2, 3]\ntry:\n    print(nums[10])\nexcept IndexError:\n    print("索引超出范围！列表只有", len(nums), "个元素")', check:function(o){return o.indexOf("索引")!==-1 || o.indexOf("范围")!==-1;}},
  {desc:"用try/except捕获KeyError", template:'d = {"name": "小明"}\n', hint:'d = {"name": "小明"}\ntry:\n    print(d["age"])\nexcept KeyError as e:\n    print(f"键{e}不存在")', check:function(o){return o.indexOf("不存在")!==-1;}},
  {desc:"用finally确保清理操作一定执行", template:'# finally用法\n', hint:'try:\n    print("开始执行")\n    x = 1 / 0\nexcept ZeroDivisionError:\n    print("捕获到除零错误")\nfinally:\n    print("清理操作（一定会执行）")', check:function(o){return o.indexOf("清理")!==-1;}},
  {desc:"写一个函数安全地将字符串转为整数列表", template:'# 安全转换列表\n', hint:'def safe_int_list(str_list):\n    result = []\n    for s in str_list:\n        try:\n            result.append(int(s))\n        except ValueError:\n            print(f"跳过非数字: {s}")\n    return result\nprint(safe_int_list(["1","2","abc","4","xyz"]))', check:function(o){return o.indexOf("跳过")!==-1;}},
  {desc:"用多个except分别处理不同类型的错误", template:'# 多重异常处理\n', hint:'def process(data):\n    try:\n        num = int(data)\n        result = 100 / num\n        print(f"结果: {result}")\n    except ValueError:\n        print("不是有效数字")\n    except ZeroDivisionError:\n        print("不能为零")\nprocess("abc")\nprocess("0")\nprocess("5")', check:function(o){return o.indexOf("结果")!==-1;}},
  {desc:"自定义一个异常类 AgeError 并使用它", template:'# 自定义异常\n', hint:'class AgeError(Exception):\n    pass\ndef check_age(age):\n    if age < 0 or age > 150:\n        raise AgeError(f"年龄{age}不合理")\n    print(f"年龄{age}合法")\ntry:\n    check_age(25)\n    check_age(200)\nexcept AgeError as e:\n    print(f"错误: {e}")', check:function(o){return o.indexOf("合法")!==-1 && o.indexOf("错误")!==-1;}},
  {desc:"用嵌套try/except处理多层可能的错误", template:'# 嵌套异常\n', hint:'def divide_items(items, divisor):\n    results = []\n    for item in items:\n        try:\n            try:\n                num = float(item)\n            except ValueError:\n                print(f"跳过非数字: {item}")\n                continue\n            results.append(num / divisor)\n        except ZeroDivisionError:\n            print("除数为零")\n    return results\nprint(divide_items(["10","abc","20"], 5))', check:function(o){return o.indexOf("跳过")!==-1;}},
  {desc:"实现一个重试机制：操作失败时重试最多3次", template:'import random\n', hint:'import random\ndef unstable_operation():\n    if random.random() < 0.7:\n        raise Exception("操作失败")\n    return "成功"\nfor attempt in range(1, 4):\n    try:\n        result = unstable_operation()\n        print(f"第{attempt}次: {result}")\n        break\n    except Exception as e:\n        print(f"第{attempt}次: {e}")\nelse:\n    print("3次都失败了")', check:function(o){return o.indexOf("次")!==-1;}},
  {desc:"写一个安全的列表平均值函数（处理空列表和非数字）", template:'# 安全平均值\n', hint:'def safe_average(lst):\n    if not lst:\n        return "列表为空"\n    total = 0\n    count = 0\n    for item in lst:\n        try:\n            total += float(item)\n            count += 1\n        except (ValueError, TypeError):\n            print(f"跳过: {item}")\n    return total/count if count > 0 else 0\nprint(safe_average([10, 20, "abc", 30]))', check:function(o){return o.indexOf("20")!==-1 || o.indexOf("跳过")!==-1;}}
],
