  {desc:"计算每个学生与平均分的差距", template:'students = {"小明":95,"小红":87,"小刚":72,"小李":88}\n', hint:'students = {"小明":95,"小红":87,"小刚":72,"小李":88}\navg = sum(students.values())/len(students)\nfor name, score in students.items():\n    diff = score - avg\n    print(f"{name}: {score}分 ({"+" if diff>=0 else ""}{diff:.1f})")', check:function(o){return o.indexOf("分")!==-1;}},
  {desc:"添加新学生并重新排序", template:'students = [{"name":"小明","score":95}]\n', hint:'students = [{"name":"小明","score":95}]\ndef add_student(data, name, score):\n    data.append({"name":name,"score":score})\n    data.sort(key=lambda x: x["score"], reverse=True)\nadd_student(students, "小红", 88)\nadd_student(students, "小刚", 92)\nfor s in students:\n    print(f"{s[\"name\"]}: {s[\"score\"]}分")', check:function(o){return o.indexOf("分")!==-1;}},
  {desc:"统计及格率和优秀率", template:'scores = [95,87,72,88,93,66,78,55,91,45]\n', hint:'scores = [95,87,72,88,93,66,78,55,91,45]\ntotal = len(scores)\npass_rate = sum(1 for s in scores if s >= 60) / total * 100\nexc_rate = sum(1 for s in scores if s >= 90) / total * 100\nprint(f"及格率: {pass_rate:.0f}%")\nprint(f"优秀率: {exc_rate:.0f}%")', check:function(o){return o.indexOf("%")!==-1;}},
  {desc:"查找成绩进步最大的学生（比较两次考试）", template:'# 两次成绩\n', hint:'exam1 = {"小明":80,"小红":75,"小刚":60}\nexam2 = {"小明":85,"小红":90,"小刚":70}\nbest = ""\nmax_imp = 0\nfor name in exam1:\n    imp = exam2[name] - exam1[name]\n    if imp > max_imp:\n        max_imp = imp\n        best = name\nprint(f"进步最大: {best} (+{max_imp}分)")', check:function(o){return o.indexOf("进步")!==-1;}},
  {desc:"用函数实现成绩单打印（带表头和分隔线）", template:'# 成绩单\n', hint:'students = [("小明",95),("小红",88),("小刚",72)]\nprint("=" * 20)\nprint(f"{"姓名":^8}{"成绩":^8}")\nprint("-" * 20)\nfor name, score in students:\n    print(f"{name:^8}{score:^8}")\nprint("=" * 20)', check:function(o){return o.indexOf("===")!==-1 || o.indexOf("姓名")!==-1;}},
  {desc:"实现简易的成绩查询系统（按名字或分数范围查询）", template:'# 查询系统\n', hint:'students = [("小明",95),("小红",88),("小刚",72),("小李",90)]\ndef query_by_range(data, low, high):\n    return [(n,s) for n,s in data if low <= s <= high]\nresult = query_by_range(students, 80, 95)\nfor name, score in result:\n    print(f"{name}: {score}分")', check:function(o){return o.indexOf("分")!==-1;}}
