  {desc:"评估密码强度（长度、大小写、数字、特殊字符）", template:'# 密码强度\n', hint:'def strength(pwd):\n    score = 0\n    if len(pwd) >= 8: score += 1\n    if any(c.isupper() for c in pwd): score += 1\n    if any(c.islower() for c in pwd): score += 1\n    if any(c.isdigit() for c in pwd): score += 1\n    levels = ["弱","中","强","很强","极强"]\n    return levels[score]\nfor p in ["123","abc123","Abc123!@"]:\n    print(f"{p}: {strength(p)}")', check:function(o){return o.indexOf("强")!==-1;}},
  {desc:"生成容易记忆的密码（单词+数字组合）", template:'import random\n', hint:'import random\nwords = ["apple","blue","cat","dog","egg"]\nw1 = random.choice(words).capitalize()\nw2 = random.choice(words)\nn = random.randint(10,99)\npwd = f"{w1}{n}{w2}"\nprint(f"密码: {pwd}")', check:function(o){return o.indexOf("密码")!==-1;}},
  {desc:"批量生成5个不同的密码", template:'import random\n', hint:'import random\nchars = "abcdefghijkmnpqrstuvwxyz23456789"\nfor i in range(5):\n    pwd = "".join(random.choice(chars) for _ in range(8))\n    print(f"密码{i+1}: {pwd}")', check:function(o){return o.indexOf("密码5")!==-1;}},
  {desc:"生成密码并检查是否包含连续字符（如abc、123）", template:'import random\n', hint:'import random\ndef has_sequence(pwd):\n    for i in range(len(pwd)-2):\n        if ord(pwd[i+1])==ord(pwd[i])+1 and ord(pwd[i+2])==ord(pwd[i])+2:\n            return True\n    return False\nchars = "abcdefghijkmnpqrstuvwxyz23456789"\npwd = "".join(random.choice(chars) for _ in range(10))\nprint(f"密码: {pwd}")\nprint(f"有连续字符: {has_sequence(pwd)}")', check:function(o){return o.indexOf("密码")!==-1;}},
  {desc:"密码生成器加入排除相似字符功能（如0和O、1和l）", template:'import random\n', hint:'import random\nchars = "abcdefghjkmnpqrstuvwxyzABCDEFGHJKMNPQRSTUVWXYZ23456789"\npwd = "".join(random.choice(chars) for _ in range(12))\nprint(f"密码(无歧义): {pwd}")', check:function(o){return o.indexOf("密码")!==-1;}},
  {desc:"实现密码加密存储（简单的替换加密）", template:'# 密码加密\n', hint:'def encrypt(pwd, key=3):\n    return "".join(chr(ord(c)+key) for c in pwd)\ndef decrypt(enc, key=3):\n    return "".join(chr(ord(c)-key) for c in enc)\npwd = "Hello123"\nenc = encrypt(pwd)\nprint(f"原文: {pwd}")\nprint(f"加密: {enc}")\nprint(f"解密: {decrypt(enc)}")', check:function(o){return o.indexOf("加密")!==-1;}},
  {desc:"把密码生成器封装成类 PasswordGenerator", template:'import random\n', hint:'import random\nclass PasswordGenerator:\n    def __init__(self):\n        self.chars = "abcdefghijkmnpqrstuvwxyzABCDEFGHJKMNPQRSTUVWXYZ23456789!@#$"\n    def generate(self, length=12):\n        return "".join(random.choice(self.chars) for _ in range(length))\npg = PasswordGenerator()\nfor _ in range(3):\n    print(pg.generate())', check:function(o){return o.trim().split("\n").length>=3;}}
