  {desc:"叠加多个装饰器", template:'# 多重装饰\n', hint:'def bold(func):\n    def wrapper(): return "**" + func() + "**"\n    return wrapper\ndef italic(func):\n    def wrapper(): return "_" + func() + "_"\n    return wrapper\n@bold\n@italic\ndef greet():\n    return "Hello"\nprint(greet())', check:function(o){return o.indexOf("**_Hello_**")!==-1;}},
  {desc:"写一个限制函数调用次数的装饰器", template:'# 调用次数限制\n', hint:'def limit_calls(max_calls):\n    def decorator(func):\n        count = [0]\n        def wrapper(*args):\n            if count[0] >= max_calls:\n                print(f"已达到{max_calls}次上限")\n                return\n            count[0] += 1\n            return func(*args)\n        return wrapper\n    return decorator\n@limit_calls(3)\ndef hello():\n    print("Hello!")\nfor _ in range(5): hello()', check:function(o){return o.indexOf("上限")!==-1;}},
  {desc:"写一个装饰器验证函数参数类型", template:'# 类型检查\n', hint:'def check_types(*types):\n    def decorator(func):\n        def wrapper(*args):\n            for a, t in zip(args, types):\n                if not isinstance(a, t):\n                    print(f"参数类型错误: 期望{t.__name__}, 得到{type(a).__name__}")\n                    return\n            return func(*args)\n        return wrapper\n    return decorator\n@check_types(int, int)\ndef add(a, b):\n    return a + b\nprint(add(1, 2))\nadd("1", 2)', check:function(o){return o.indexOf("3")!==-1;}},
  {desc:"写一个retry装饰器（失败时自动重试）", template:'import random\n', hint:'import random\ndef retry(times):\n    def decorator(func):\n        def wrapper(*args):\n            for i in range(times):\n                try:\n                    return func(*args)\n                except Exception as e:\n                    print(f"第{i+1}次失败: {e}")\n            print("全部重试失败")\n        return wrapper\n    return decorator\n@retry(3)\ndef risky():\n    if random.random() < 0.7:\n        raise Exception("运气不好")\n    return "成功!"\nresult = risky()\nif result: print(result)', check:function(o){return true;}}
