  {desc:"用vars()获取对象的__dict__", template:'# vars()\n', hint:'class Student:\n    def __init__(self, name, score):\n        self.name = name\n        self.score = score\ns = Student("小红", 95)\nprint(vars(s))\nfor k, v in vars(s).items():\n    print(f"  {k}: {v}")', check:function(o){return o.indexOf("name")!==-1;}}
