  {desc:"创建一个带错误码的自定义异常", template:'# 带错误码\n', hint:'class AppError(Exception):\n    def __init__(self, code, msg):\n        self.code = code\n        self.msg = msg\n        super().__init__(f"[{code}] {msg}")\ntry:\n    raise AppError(404, "页面未找到")\nexcept AppError as e:\n    print(f"错误码:{e.code} 信息:{e.msg}")', check:function(o){return o.indexOf("404")!==-1;}},
  {desc:"在函数中验证参数并raise TypeError", template:'# 参数验证\n', hint:'def add(a, b):\n    if not isinstance(a, (int,float)):\n        raise TypeError(f"a必须是数字，得到{type(a).__name__}")\n    if not isinstance(b, (int,float)):\n        raise TypeError(f"b必须是数字，得到{type(b).__name__}")\n    return a + b\nprint(add(3, 5))\ntry: add("3", 5)\nexcept TypeError as e: print(e)', check:function(o){return o.indexOf("8")!==-1;}},
  {desc:"raise不带参数重新抛出当前异常", template:'# 原样抛出\n', hint:'def risky_operation():\n    raise RuntimeError("出错了")\ndef wrapper():\n    try:\n        risky_operation()\n    except RuntimeError:\n        print("记录日志...")\n        raise\ntry:\n    wrapper()\nexcept RuntimeError as e:\n    print(f"最终捕获: {e}")', check:function(o){return o.indexOf("最终捕获")!==-1;}},
  {desc:"创建异常层次结构", template:'# 异常层次\n', hint:'class AppError(Exception): pass\nclass ValidationError(AppError): pass\nclass AuthError(AppError): pass\ntry:\n    raise ValidationError("邮箱格式不对")\nexcept AppError as e:\n    print(f"应用错误: {type(e).__name__}: {e}")', check:function(o){return o.indexOf("ValidationError")!==-1;}},
  {desc:"用assert进行调试断言", template:'# assert\n', hint:'def average(nums):\n    assert len(nums) > 0, "列表不能为空"\n    return sum(nums) / len(nums)\nprint(average([1,2,3]))\ntry:\n    average([])\nexcept AssertionError as e:\n    print(f"断言失败: {e}")', check:function(o){return o.indexOf("2")!==-1;}},
  {desc:"条件性地raise异常", template:'# 条件raise\n', hint:'def withdraw(balance, amount):\n    if amount <= 0:\n        raise ValueError("取款金额必须为正")\n    if amount > balance:\n        raise ValueError(f"余额不足(余额:{balance}，要取:{amount})")\n    return balance - amount\ntry:\n    print(withdraw(100, 30))\n    print(withdraw(100, 200))\nexcept ValueError as e:\n    print(f"错误: {e}")', check:function(o){return o.indexOf("70")!==-1 && o.indexOf("余额不足")!==-1;}},
  {desc:"综合：实现一个带完整验证的用户注册函数", template:'# 用户注册\n', hint:'class RegistrationError(Exception): pass\ndef register(username, password, email):\n    if len(username) < 3: raise RegistrationError("用户名至少3个字符")\n    if len(password) < 6: raise RegistrationError("密码至少6位")\n    if "@" not in email: raise RegistrationError("邮箱格式不正确")\n    print(f"注册成功: {username}")\nfor u,p,e in [("ab","123","x"),("alice","abc123","a@b.com")]:\n    try: register(u, p, e)\n    except RegistrationError as err: print(f"失败: {err}")', check:function(o){return o.indexOf("注册成功")!==-1;}}
