"14-3": [
  {desc:"写函数计算列表平均值，处理空列表和非数字", template:'# 安全平均值\n', hint:'def average(lst):\n    assert len(lst) > 0, "列表不能为空"\n    total = count = 0\n    for item in lst:\n        try: total += float(item); count += 1\n        except (ValueError, TypeError): print(f"跳过: {item}")\n    return total/count if count else 0\nprint(average([10, 20, "abc", 30]))', check:function(o){return o.indexOf("20")!==-1 || o.indexOf("跳过")!==-1;}},
  {desc:"用print调试跟踪变量变化", template:'# print调试\n', hint:'def mystery(n):\n    result = 0\n    for i in range(1, n+1):\n        result += i * i\n        print(f"  [debug] i={i}, i*i={i*i}, result={result}")\n    return result\nprint(f"结果: {mystery(5)}")', check:function(o){return o.indexOf("[debug]")!==-1;}},
  {desc:"用断言验证函数的前置条件", template:'# 前置条件\n', hint:'def binary_search(lst, target):\n    assert lst == sorted(lst), "列表必须有序"\n    lo, hi = 0, len(lst)-1\n    while lo <= hi:\n        mid = (lo+hi)//2\n        if lst[mid] == target: return mid\n        elif lst[mid] < target: lo = mid+1\n        else: hi = mid-1\n    return -1\nprint(binary_search([1,3,5,7,9], 5))', check:function(o){return o.indexOf("2")!==-1;}},
  {desc:"实现一个简单的日志级别系统", template:'# 日志系统\n', hint:'def log(level, msg):\n    levels = {"DEBUG":0,"INFO":1,"WARN":2,"ERROR":3}\n    if levels.get(level, 0) >= levels["INFO"]:\n        print(f"[{level}] {msg}")\nlog("DEBUG", "详细信息")\nlog("INFO", "正常运行")\nlog("WARN", "注意")\nlog("ERROR", "出错了")', check:function(o){return o.indexOf("[INFO]")!==-1 && o.indexOf("[ERROR]")!==-1;}},
  {desc:"用try/except包装文件操作", template:'# 安全文件操作\n', hint:'def safe_read(filename):\n    try:\n        with open(filename) as f:\n            return f.read()\n    except FileNotFoundError:\n        print(f"文件{filename}不存在")\n        return ""\n    except PermissionError:\n        print(f"没有权限读取{filename}")\n        return ""\nresult = safe_read("不存在的文件.txt")\nprint(f"读取结果: \\"{result}\\"")', check:function(o){return o.indexOf("不存在")!==-1;}},
  {desc:"调试技巧：用格式化字符串打印复杂数据结构", template:'# 格式化调试\n', hint:'data = {"users": [{"name":"A","age":20},{"name":"B","age":25}]}\nprint("=== 调试数据 ===")\nfor i, user in enumerate(data["users"]):\n    print(f"  用户{i}: ", end="")\n    for k, v in user.items():\n        print(f"{k}={v} ", end="")\n    print()\nprint("================")', check:function(o){return o.indexOf("用户")!==-1;}},
  {desc:"实现一个断言工具库", template:'# 断言工具\n', hint:'def assert_equal(actual, expected, msg=""):\n    if actual != expected:\n        print(f"❌ {msg}: 期望{expected}，得到{actual}")\n    else:\n        print(f"✅ {msg}: 通过")\nassert_equal(1+1, 2, "加法")\nassert_equal("hello".upper(), "HELLO", "大写")\nassert_equal(len([1,2,3]), 4, "长度")', check:function(o){return o.indexOf("✅")!==-1 && o.indexOf("❌")!==-1;}},
  {desc:"用异常处理实现优雅降级", template:'# 优雅降级\n', hint:'def get_data(source):\n    sources = {\n        "api": lambda: 1/0,\n        "cache": lambda: {"data": "缓存数据"},\n        "default": lambda: {"data": "默认数据"}\n    }\n    for name in [source, "cache", "default"]:\n        try:\n            result = sources[name]()\n            print(f"从{name}获取成功")\n            return result\n        except Exception:\n            print(f"{name}失败，尝试下一个...")\nprint(get_data("api"))', check:function(o){return o.indexOf("成功")!==-1;}},
  {desc:"写一个调试用的计时上下文管理器", template:'import time\n', hint:'import time\nclass Timer:\n    def __init__(self, name): self.name = name\n    def __enter__(self):\n        self.start = time.time()\n        return self\n    def __exit__(self, *args):\n        elapsed = time.time() - self.start\n        print(f"[{self.name}] 耗时: {elapsed:.4f}秒")\nwith Timer("求和"):\n    total = sum(range(100000))\n    print(f"结果: {total}")', check:function(o){return o.indexOf("耗时")!==-1;}},
  {desc:"综合：实现一个带详细错误报告的数据处理器", template:'# 数据处理器\n', hint:'def process_records(records):\n    results = []\n    errors = []\n    for i, record in enumerate(records):\n        try:\n            name = record["name"]\n            score = int(record["score"])\n            results.append(f"{name}: {score}分")\n        except KeyError as e:\n            errors.append(f"记录{i}: 缺少字段{e}")\n        except ValueError:\n            errors.append(f"记录{i}: 分数格式错误")\n    for r in results: print(r)\n    if errors:\n        print("--- 错误 ---")\n        for e in errors: print(e)\ndata = [{"name":"小明","score":"95"},{"name":"小红"},{"name":"小刚","score":"abc"}]\nprocess_records(data)', check:function(o){return o.indexOf("小明")!==-1;}}
],
