  {desc:"用列表模拟文件的seek操作", template:'# 模拟seek\n', hint:'class MemFile:\n    def __init__(self, data): self.data = data; self.pos = 0\n    def read(self, n=-1):\n        if n < 0: result = self.data[self.pos:]; self.pos = len(self.data)\n        else: result = self.data[self.pos:self.pos+n]; self.pos += n\n        return result\n    def seek(self, pos): self.pos = pos\nf = MemFile("Hello World Python")\nprint(f.read(5))\nf.seek(6)\nprint(f.read(5))', check:function(o){return o.indexOf("Hello")!==-1 && o.indexOf("World")!==-1;}},
  {desc:"实现内存中的键值存储", template:'# 键值存储\n', hint:'class MemoryStore:\n    def __init__(self): self.data = {}\n    def put(self, key, val): self.data[key] = val\n    def get(self, key): return self.data.get(key)\n    def dump(self):\n        import json\n        return json.dumps(self.data, ensure_ascii=False)\nstore = MemoryStore()\nstore.put("name", "小明")\nstore.put("age", 10)\nprint(store.dump())\nprint(store.get("name"))', check:function(o){return o.indexOf("小明")!==-1;}},
  {desc:"模拟文件的追加和读取", template:'# 追加模式\n', hint:'buffer = ""\nbuffer += "第一行\\n"\nbuffer += "第二行\\n"\nbuffer += "第三行\\n"\nprint("内容:")\nprint(buffer)\nprint(f"共{len(buffer.strip().split(chr(10)))}行")', check:function(o){return o.indexOf("第一行")!==-1;}},
  {desc:"综合：用内存流实现一个简单的模板引擎", template:'# 模板引擎\n', hint:'def render(template, data):\n    result = template\n    for key, val in data.items():\n        result = result.replace("{{" + key + "}}", str(val))\n    return result\ntpl = "你好，{{name}}！你今年{{age}}岁了。"\nprint(render(tpl, {"name":"小明","age":10}))', check:function(o){return o.indexOf("小明")!==-1 && o.indexOf("10岁")!==-1;}}
